const { Manifold, CrossSection, setCircularSegments } = api;
setCircularSegments(64);

// ── STEAMPUNK NASA ROCKET ──
// Units: arbitrary (think ~1 unit = 5cm)
// Total height ~200 units, radius ~10 units

const SEG = 64;

// ─────────────────────────────────────────
// 1. MAIN BODY — large cylindrical fuselage
// ─────────────────────────────────────────
const bodyProfile = CrossSection.ofPolygons([[
  [0, 0], [10, 0], [10, 80], [0, 80]
]]);
const mainBody = api.label(bodyProfile.revolve(SEG), 'mainBody');

// ─────────────────────────────────────────
// 2. NOSE CONE — ogive-style tapered tip
// ─────────────────────────────────────────
// Build an ogive nose cone as a series of profile points
const nosePoints = [[0, 0]];
const noseH = 40;
const noseR = 10;
for (let i = 0; i <= 20; i++) {
  const t = i / 20;
  const r = noseR * Math.sqrt(1 - t * t); // circular arc = ogive shape
  nosePoints.push([r, noseH * t]);
}
nosePoints.push([0, noseH]);
const noseProfile = CrossSection.ofPolygons([nosePoints]);
const noseCone = api.label(noseProfile.revolve(SEG).translate([0, 0, 80]), 'noseCone');

// ─────────────────────────────────────────
// 3. UPPER STAGE — narrower second stage
// ─────────────────────────────────────────
const upperStageProfile = CrossSection.ofPolygons([[
  [0, 0], [7, 0], [7, 40], [0, 40]
]]);
const upperStage = api.label(upperStageProfile.revolve(SEG).translate([0, 0, 120]), 'upperStage');

// ─────────────────────────────────────────
// 4. INTERSTAGE — frustum connecting stages
// ─────────────────────────────────────────
const interstageProfile = CrossSection.ofPolygons([[
  [0, 0], [10, 0], [10, 2], [7, 8], [7, 10], [0, 10]
]]);
const interstage = api.label(interstageProfile.revolve(SEG).translate([0, 0, 118]), 'interstage');

// ─────────────────────────────────────────
// 5. UPPER NOSE — small ogive on top stage
// ─────────────────────────────────────────
const upperNoseH = 20;
const upperNoseR = 7;
const upperNosePoints = [[0, 0]];
for (let i = 0; i <= 16; i++) {
  const t = i / 16;
  const r = upperNoseR * Math.sqrt(1 - t * t);
  upperNosePoints.push([r, upperNoseH * t]);
}
upperNosePoints.push([0, upperNoseH]);
const upperNoseProfile = CrossSection.ofPolygons([upperNosePoints]);
const upperNose = api.label(upperNoseProfile.revolve(SEG).translate([0, 0, 160]), 'upperNose');

// ─────────────────────────────────────────
// 6. ENGINE BELL — bottom nozzle cluster
// ─────────────────────────────────────────
// Single large engine bell
const bellProfile = CrossSection.ofPolygons([[
  [0, 0], [4, 0], [4, 1], [7, 8], [7, 10], [6, 10],
  [3, 3], [3, 1], [0.5, 1], [0.5, 0]
]]);
const centerBell = api.label(bellProfile.revolve(SEG).translate([0, 0, -10]), 'engineBells');

// Four surrounding smaller bells
const smallBellProfile = CrossSection.ofPolygons([[
  [0, 0], [2.5, 0], [2.5, 0.5], [4.5, 6], [4.5, 7.5], [3.8, 7.5],
  [1.8, 1.2], [1.8, 0.5], [0.3, 0.5], [0.3, 0]
]]);
const smallBell = smallBellProfile.revolve(SEG);
const bells = [0, 1, 2, 3].map(i => {
  const angle = i * 90;
  return smallBell
    .translate([6.5, 0, -9])
    .rotate([0, 0, angle]);
});
const engineBells2 = api.label(
  bells.reduce((acc, b) => acc.add(b), Manifold.cube([0.001,0.001,0.001]).translate([1000,0,0])).subtract(Manifold.cube([0.001,0.001,0.001]).translate([1000,0,0])),
  'engineBells2'
);
// Actually let's union them properly
const allSmallBells = bells[0].add(bells[1]).add(bells[2]).add(bells[3]);
const engineBells2Labeled = api.label(allSmallBells, 'engineBells2');

// ─────────────────────────────────────────
// 7. ENGINE SECTION (bottom fairing)
// ─────────────────────────────────────────
const engineFairingProfile = CrossSection.ofPolygons([[
  [0, 0], [10, 0], [10, 2], [11.5, 5], [11.5, 7], [10, 7], [10, 8],
  [0, 8]
]]);
const engineFairing = api.label(engineFairingProfile.revolve(SEG).translate([0, 0, -8]), 'engineFairing');

// ─────────────────────────────────────────
// 8. FINS — 4 large delta fins
// ─────────────────────────────────────────
// Each fin is a swept/extruded shape
// Fin polygon: swept delta shape with thickness
const finH = 35;
const finDepth = 20;
const finThick = 1.5;

// Delta fin cross section extruded and positioned
const finShape = CrossSection.ofPolygons([[
  [0, 0], [finDepth, 0], [0, finH]
]]);
const finSolid = finShape.extrude(finThick).translate([-finThick/2, 0, 0])
  .rotate([90, 0, 0])
  .translate([10, 0, 0]);

const fins = [0, 1, 2, 3].map(i => {
  return finSolid.rotate([0, 0, i * 90]);
});
const allFins = fins[0].add(fins[1]).add(fins[2]).add(fins[3]);
const finsLabeled = api.label(allFins, 'fins');

// ─────────────────────────────────────────
// 9. STEAMPUNK DETAILS — copper rings / bands
// ─────────────────────────────────────────
// Decorative riveted rings at body junctions
const makeRing = (z, innerR, outerR, h) => {
  const ringProfile = CrossSection.ofPolygons([[
    [innerR, 0], [outerR, 0], [outerR, h], [innerR, h]
  ]]);
  return ringProfile.revolve(SEG).translate([0, 0, z]);
};

const ring1 = makeRing(20, 9.8, 11.2, 2.5);
const ring2 = makeRing(40, 9.8, 11.2, 2.5);
const ring3 = makeRing(60, 9.8, 11.2, 2.5);
const ring4 = makeRing(76, 9.8, 11.0, 3);  // just below nose cone join
const ring5 = makeRing(122, 6.8, 8.2, 2);  // upper stage bottom
const ring6 = makeRing(148, 6.8, 8.2, 2);  // upper stage middle
const allRings = ring1.add(ring2).add(ring3).add(ring4).add(ring5).add(ring6);
const ringsLabeled = api.label(allRings, 'rings');

// ─────────────────────────────────────────
// 10. STEAMPUNK PIPES — 4 external pipes
// ─────────────────────────────────────────
const pipeRadius = 0.8;
const pipeSeg = 16;
const makePipe = (offsetX, zBot, zTop) => {
  const pipeProfile = CrossSection.ofPolygons([[
    [pipeRadius - 0.15, 0], [pipeRadius, 0], [pipeRadius, zTop - zBot], [pipeRadius - 0.15, zTop - zBot]
  ]]);
  const pipe = pipeProfile.revolve(pipeSeg).translate([offsetX, 0, zBot]);
  // Pipe collar rings
  const collarProf = CrossSection.ofPolygons([[
    [pipeRadius - 0.15, 0], [pipeRadius + 0.4, 0], [pipeRadius + 0.4, 1.5], [pipeRadius - 0.15, 1.5]
  ]]);
  const collar1 = collarProf.revolve(pipeSeg).translate([offsetX, 0, zBot + 5]);
  const collar2 = collarProf.revolve(pipeSeg).translate([offsetX, 0, zTop - 7]);
  return pipe.add(collar1).add(collar2);
};

const pipe1 = makePipe(11.8, 5, 75);
const pipe2 = makePipe(11.8, 5, 75).rotate([0, 0, 90]);
const pipe3 = makePipe(11.8, 5, 75).rotate([0, 0, 180]);
const pipe4 = makePipe(11.8, 5, 75).rotate([0, 0, 270]);
const allPipes = pipe1.add(pipe2).add(pipe3).add(pipe4);
const pipesLabeled = api.label(allPipes, 'pipes');

// ─────────────────────────────────────────
// 11. RIVETS along pipe lines
// ─────────────────────────────────────────
const makeRivetRow = (offsetX, zStart, count, spacing) => {
  let result = null;
  for (let i = 0; i < count; i++) {
    const rivet = Manifold.sphere(0.5, 8).translate([offsetX, 0, zStart + i * spacing]);
    result = result ? result.add(rivet) : rivet;
  }
  return result;
};

const rivRow1 = makeRivetRow(10.5, 8, 9, 8);
const rivRow2 = rivRow1.rotate([0, 0, 90]);
const rivRow3 = rivRow1.rotate([0, 0, 180]);
const rivRow4 = rivRow1.rotate([0, 0, 270]);
const allRivets = rivRow1.add(rivRow2).add(rivRow3).add(rivRow4);
const rivetsLabeled = api.label(allRivets, 'rivets');

// ─────────────────────────────────────────
// 12. PORTHOLES — 4 circular windows
// ─────────────────────────────────────────
// Porthole: sphere subtracted to create circular recess + frame ring
const portholePunchR = 2.2;
const portholePunch = Manifold.sphere(portholePunchR, 16);
const portholeFrame = Manifold.sphere(portholePunchR + 0.5, 16);
const porthole = portholeFrame.subtract(portholePunch);

const ph1 = porthole.translate([10, 0, 50]);
const ph2 = ph1.rotate([0, 0, 90]);
const ph3 = ph1.rotate([0, 0, 180]);
const ph4 = ph1.rotate([0, 0, 270]);
const allPortholes = ph1.add(ph2).add(ph3).add(ph4);
const portholesLabeled = api.label(allPortholes, 'portholes');

// ─────────────────────────────────────────
// UNION EVERYTHING
// ─────────────────────────────────────────
const rocket = mainBody
  .add(noseCone)
  .add(upperStage)
  .add(interstage)
  .add(upperNose)
  .add(centerBell)
  .add(engineBells2Labeled)
  .add(engineFairing)
  .add(finsLabeled)
  .add(ringsLabeled)
  .add(pipesLabeled)
  .add(rivetsLabeled)
  .add(portholesLabeled);

return rocket;
